import{c as e,Q as a,j as l,m as n}from"./chunks/framework.CQqJojvj.js";const f=JSON.parse('{"title":"06 - Kafka","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/06-kafka.md","filePath":"bagu/06-kafka.md","lastUpdated":null}'),r={name:"bagu/06-kafka.md"};function s(d,t,i,o,c,h){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="_06-kafka" tabindex="-1">06 - Kafka <a class="header-anchor" href="#_06-kafka" aria-label="Permalink to &quot;06 - Kafka&quot;">​</a></h1><blockquote><p>Kafka 是分布式消息队列的事实标准。高吞吐、持久化、水平扩展是核心特性，面试重点在可靠性保证和性能优化。</p></blockquote><hr><h2 id="_1-基本架构" tabindex="-1">1. 基本架构 <a class="header-anchor" href="#_1-基本架构" aria-label="Permalink to &quot;1. 基本架构&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer → Kafka Cluster (Broker × N) → Consumer</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>          ZooKeeper / KRaft</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">Broker</td><td style="text-align:left;">Kafka 服务节点，负责存储和转发消息</td></tr><tr><td style="text-align:left;">Topic</td><td style="text-align:left;">消息的逻辑分类</td></tr><tr><td style="text-align:left;">Partition</td><td style="text-align:left;">Topic 的物理分片，有序、不可变的消息序列</td></tr><tr><td style="text-align:left;">Producer</td><td style="text-align:left;">消息生产者</td></tr><tr><td style="text-align:left;">Consumer</td><td style="text-align:left;">消息消费者</td></tr><tr><td style="text-align:left;">Consumer Group</td><td style="text-align:left;">消费者组，组内每个消费者负责不同分区</td></tr><tr><td style="text-align:left;">Replica</td><td style="text-align:left;">分区副本（Leader + Follower）</td></tr></tbody></table><hr><h2 id="_2-高吞吐原理" tabindex="-1">2. 高吞吐原理 <a class="header-anchor" href="#_2-高吞吐原理" aria-label="Permalink to &quot;2. 高吞吐原理&quot;">​</a></h2><ol><li><strong>顺序写入</strong> — 将消息追加到日志文件末尾，利用磁盘顺序写的高性能（比随机写快 6000+ 倍）</li><li><strong>Page Cache</strong> — 利用 OS 页缓存，写入时先写页缓存，由 OS 异步刷盘</li><li><strong>零拷贝</strong> — 发送数据时通过 <code>sendfile()</code> 系统调用，数据从 Page Cache 直接拷贝到网卡，不经过用户态</li><li><strong>批量压缩</strong> — Producer 批量发送 + 消息压缩（gzip/snappy/lz4/zstd）</li><li><strong>分区并行</strong> — 多个分区可以并行读写，水平扩展</li></ol><hr><h2 id="_3-消息可靠性" tabindex="-1">3. 消息可靠性 <a class="header-anchor" href="#_3-消息可靠性" aria-label="Permalink to &quot;3. 消息可靠性&quot;">​</a></h2><h3 id="producer-可靠性" tabindex="-1">Producer 可靠性 <a class="header-anchor" href="#producer-可靠性" aria-label="Permalink to &quot;Producer 可靠性&quot;">​</a></h3><p><strong>acks 参数：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">值</th><th style="text-align:left;">含义</th><th style="text-align:left;">可靠性</th></tr></thead><tbody><tr><td style="text-align:left;"><code>acks=0</code></td><td style="text-align:left;">不等待确认</td><td style="text-align:left;">可能丢失</td></tr><tr><td style="text-align:left;"><code>acks=1</code></td><td style="text-align:left;">Leader 写入后确认</td><td style="text-align:left;">可能丢（Leader 宕机前 Follower 未同步）</td></tr><tr><td style="text-align:left;"><code>acks=all</code> / <code>-1</code></td><td style="text-align:left;">所有 ISR 确认后返回</td><td style="text-align:left;">最高可靠性 ✅</td></tr></tbody></table><p><strong>幂等性：</strong> <code>enable.idempotence=true</code>，Producer 自动去重，保证单分区内的消息不重复。</p><h3 id="broker-可靠性" tabindex="-1">Broker 可靠性 <a class="header-anchor" href="#broker-可靠性" aria-label="Permalink to &quot;Broker 可靠性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">机制</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">多副本（Replication）</td><td style="text-align:left;">每个分区有多个副本，Leader 负责读写，Follower 同步备份</td></tr><tr><td style="text-align:left;">ISR（In-Sync Replica）</td><td style="text-align:left;">与 Leader 保持同步的副本集合</td></tr><tr><td style="text-align:left;">不完全首领选举(<code>unclean.leader.election</code>)</td><td style="text-align:left;"><code>false</code> 时，ISR 外副本不能选为 Leader，保证数据不丢</td></tr><tr><td style="text-align:left;"><code>min.insync.replicas</code></td><td style="text-align:left;">最少同步副本数，搭配 <code>acks=all</code> 使用</td></tr></tbody></table><h3 id="consumer-可靠性" tabindex="-1">Consumer 可靠性 <a class="header-anchor" href="#consumer-可靠性" aria-label="Permalink to &quot;Consumer 可靠性&quot;">​</a></h3><ul><li><strong>手动提交 offset</strong> — 处理完消息再提交，实现至少一次/最多一次语义</li><li><strong>Rebalance 防范</strong> — 控制处理时间 &lt; <code>max.poll.interval.ms</code>（默认 5min），避免被踢出消费者组</li></ul><hr><h2 id="_4-消息不丢-不重的配置" tabindex="-1">4. 消息不丢 / 不重的配置 <a class="header-anchor" href="#_4-消息不丢-不重的配置" aria-label="Permalink to &quot;4. 消息不丢 / 不重的配置&quot;">​</a></h2><h3 id="不丢消息" tabindex="-1">不丢消息 <a class="header-anchor" href="#不丢消息" aria-label="Permalink to &quot;不丢消息&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer: acks=all, enable.idempotence=true, retries=MAX</span></span>
<span class="line"><span>Broker:   replication.factor=3, min.insync.replicas=2, unclean.leader.election=false</span></span>
<span class="line"><span>Consumer: enable.auto.commit=false, 手动提交offset（处理完再提交）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="不重消息-精确一次语义" tabindex="-1">不重消息（精确一次语义） <a class="header-anchor" href="#不重消息-精确一次语义" aria-label="Permalink to &quot;不重消息（精确一次语义）&quot;">​</a></h3><ol><li><strong>幂等 Producer + 事务</strong> — <code>enable.idempotence=true</code> + <code>transactional.id</code></li><li><strong>下游幂等处理</strong> — 基于唯一键（如订单ID）去重插入</li><li><strong>消费端手动提交</strong> — 业务处理+offset 提交在同一事务中</li></ol><hr><h2 id="_5-消费者组与-rebalance" tabindex="-1">5. 消费者组与 Rebalance <a class="header-anchor" href="#_5-消费者组与-rebalance" aria-label="Permalink to &quot;5. 消费者组与 Rebalance&quot;">​</a></h2><h3 id="消费者组" tabindex="-1">消费者组 <a class="header-anchor" href="#消费者组" aria-label="Permalink to &quot;消费者组&quot;">​</a></h3><ul><li>同一组内消费者互斥地消费不同分区</li><li>分区数 &gt;= 消费者数（否则多余消费者空闲）</li><li>不同消费者组之间独立消费（广播模式）</li></ul><h3 id="rebalance-触发条件" tabindex="-1">Rebalance 触发条件 <a class="header-anchor" href="#rebalance-触发条件" aria-label="Permalink to &quot;Rebalance 触发条件&quot;">​</a></h3><ol><li>组内消费者数量变化</li><li>Topic 分区数变化</li><li>消费者心跳超时（<code>session.timeout.ms</code>）</li></ol><h3 id="避免-rebalance-的方法" tabindex="-1">避免 Rebalance 的方法 <a class="header-anchor" href="#避免-rebalance-的方法" aria-label="Permalink to &quot;避免 Rebalance 的方法&quot;">​</a></h3><ul><li><code>max.poll.records</code> — 减小单次拉取数量（如 500）</li><li><code>max.poll.interval.ms</code> — 增大处理超时时间</li><li>避免频繁启停 Consumer</li></ul><hr><h2 id="_6-消息顺序性" tabindex="-1">6. 消息顺序性 <a class="header-anchor" href="#_6-消息顺序性" aria-label="Permalink to &quot;6. 消息顺序性&quot;">​</a></h2><p>Kafka 只保证<strong>分区内有序</strong>，不保证跨分区有序。</p><p><strong>实现全局有序：</strong> 将需要有序的消息发到<strong>同一分区</strong>（通过指定 Key 的哈希值）。</p><hr><h2 id="_7-消息积压处理" tabindex="-1">7. 消息积压处理 <a class="header-anchor" href="#_7-消息积压处理" aria-label="Permalink to &quot;7. 消息积压处理&quot;">​</a></h2><ol><li><strong>临时扩容</strong> — 增加分区数（注意与消费者数匹配）</li><li><strong>增加消费者</strong> — 但不超过分区数</li><li><strong>批量转存</strong> — 消费者快速读出来暂存到其他地方，后续慢慢处理</li><li><strong>检查消费逻辑</strong> — 是否有慢查询、死循环等性能问题</li></ol><hr><h2 id="_8-kafka-vs-其他-mq" tabindex="-1">8. Kafka vs 其他 MQ <a class="header-anchor" href="#_8-kafka-vs-其他-mq" aria-label="Permalink to &quot;8. Kafka vs 其他 MQ&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">Kafka</th><th style="text-align:left;">RocketMQ</th><th style="text-align:left;">RabbitMQ</th></tr></thead><tbody><tr><td style="text-align:left;">吞吐量</td><td style="text-align:left;">极高（百万 TPS）</td><td style="text-align:left;">高（十万 TPS）</td><td style="text-align:left;">中等（万 TPS）</td></tr><tr><td style="text-align:left;">延迟</td><td style="text-align:left;">ms 级</td><td style="text-align:left;">ms 级</td><td style="text-align:left;">μs 级</td></tr><tr><td style="text-align:left;">可靠性</td><td style="text-align:left;">高</td><td style="text-align:left;">高</td><td style="text-align:left;">高</td></tr><tr><td style="text-align:left;">事务消息</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">不支持</td></tr><tr><td style="text-align:left;">延时消息</td><td style="text-align:left;">不支持（需手动实现）</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td></tr><tr><td style="text-align:left;">适用场景</td><td style="text-align:left;">大数据、日志、流处理</td><td style="text-align:left;">电商、金融、业务消息</td><td style="text-align:left;">低延迟、复杂路由</td></tr></tbody></table>`,43)])])}const b=e(r,[["render",s]]);export{f as __pageData,b as default};
